#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007

int** createGraph(int n) {
    int** graph = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        graph[i] = (int*)malloc(n * sizeof(int));
    }
    return graph;
}

void freeGraph(int** graph, int n) {
    for (int i = 0; i < n; i++) {
        free(graph[i]);
    }
    free(graph);
}

int isIsomorphic(int** graph1, int** graph2, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (graph1[i][j] != graph2[i][j]) {
                return 0;
            }
        }
    }
    return 1;
}

int permute(int* arr, int n, int** graph, int** targetGraph) {
    if (n == 1) {
        int** permutedGraph = createGraph(n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                permutedGraph[i][j] = graph[arr[i]][arr[j]];
            }
        }
        int result = isIsomorphic(permutedGraph, targetGraph, n);
        freeGraph(permutedGraph, n);
        return result;
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        int temp = arr[n - 1];
        arr[n - 1] = arr[i];
        arr[i] = temp;
        count += permute(arr, n - 1, graph, targetGraph);
        temp = arr[n - 1];
        arr[n - 1] = arr[i];
        arr[i] = temp;
    }
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int** graph = createGraph(n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%1d", &graph[i][j]);
            }
        }
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            arr[i] = i;
        }
        int count = permute(arr, n, graph, graph);
        printf("%d\n", count % MOD);
        free(arr);
        freeGraph(graph, n);
    }
    return 0;
}

