import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[][] graph = new int[n][n];
            for (int i = 0; i < n; i++) {
                String row = scanner.next();
                for (int j = 0; j < n; j++) {
                    graph[i][j] = row.charAt(j) - '0';
                }
            }
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = i;
            }
            int count = permute(arr, n, graph, graph);
            System.out.println(count % MOD);
        }
    }

    public static int permute(int[] arr, int n, int[][] graph, int[][] targetGraph) {
        if (n == 1) {
            int[][] permutedGraph = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    permutedGraph[i][j] = graph[arr[i]][arr[j]];
                }
            }
            int result = isIsomorphic(permutedGraph, targetGraph, n);
            return result;
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            swap(arr, n - 1, i);
            count += permute(arr, n - 1, graph, targetGraph);
            swap(arr, n - 1, i);
        }
        return count;
    }

    public static boolean isIsomorphic(int[][] graph1, int[][] graph2, int n) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (graph1[i][j] != graph2[i][j]) {
                    return false;
                }
            }
        }
        return true;
    }

    public static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}

