function createGraph(n) {
    return Array(n).fill(0).map(() => Array(n).fill(0));
}

function isIsomorphic(graph1, graph2, n) {
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (graph1[i][j] !== graph2[i][j]) {
                return false;
            }
        }
    }
    return true;
}

function permute(arr, n, graph, targetGraph) {
    if (n === 1) {
        const permutedGraph = createGraph(n);
        for (let i = 0; i < n; i++) {
            for (let j = 0; j < n; j++) {
                permutedGraph[i][j] = graph[arr[i]][arr[j]];
            }
        }
        const result = isIsomorphic(permutedGraph, targetGraph, n);
        return result;
    }
    let count = 0;
    for (let i = 0; i < n; i++) {
        [arr[n - 1], arr[i]] = [arr[i], arr[n - 1]];
        count += permute(arr, n - 1, graph, targetGraph);
        [arr[n - 1], arr[i]] = [arr[i], arr[n - 1]];
    }
